new_content:
// tool calls ausführen und ggf weiter machen
	for _, toolCall := range responseMessage.ToolCalls {
		callContent, err := cs.callTool(ctx, chatContext, toolCall)
		if err != nil {
			slog.Default().Error("Fehler beim Aufruf eines Tools", "tool", toolCall.Type, "error", err)
			// Fehler als Nachricht an den Chat übergeben
			chatContext.AddMessage(&request.Message{
				Role: "tool",
				Content: fmt.Sprintf("Fehler beim Ausführen des Tools '%!s(MISSING)': %!v(MISSING)", toolCall.Function.Name, err),
			})
			continue
		}
		chatContext.AddMessage(&request.Message{
			Role: "tool",
			ToolCallId: toolCall.Id,
			Content: string(callContent),
		})
	}
